import { javascriptGenerator } from 'blockly/javascript';
import ros2HeadBlocks from '../CustomBlocks/blockJson/ros2_command_ai_HEAD.json';

const getFieldNames = (blockDef) => {
  const args = Array.isArray(blockDef.args0) ? blockDef.args0 : [];
  return args
    .filter((arg) => arg && typeof arg.name === 'string' && String(arg.type || '').startsWith('field_'))
    .map((arg) => arg.name);
};

const registerGeneratorForBlock = (blockDef) => {
  const fieldNames = getFieldNames(blockDef);

  javascriptGenerator.forBlock[blockDef.type] = function (block) {
    const params = {};
    fieldNames.forEach((fieldName) => {
      params[fieldName] = block.getFieldValue(fieldName);
    });

    const message = {
      blockType: blockDef.type,
      parameters: params,
    };

    return `console.log(${JSON.stringify(JSON.stringify(message))});\n`;
  };
};

ros2HeadBlocks
  .filter((blockDef) => blockDef && blockDef.type)
  .forEach(registerGeneratorForBlock);

export { ros2HeadBlocks };
